func TestEnvOverrides(t *testing.T) {
	tmpDir := t.TempDir()
	cfgFile := filepath.Join(tmpDir, "config.yaml")
	os.WriteFile(cfgFile, []byte("host: localhost\nport: 8080\nlog_level: info\ndebug: false\n"), 0644)

	t.Setenv("CONFIGMAN_HOST", "0.0.0.0")
	t.Setenv("CONFIGMAN_PORT", "9090")
	t.Setenv("CONFIGMAN_DEBUG", "true")

	cfg, err := Load(cfgFile)
	if err != nil {
		t.Fatal(err)
	}
	if cfg.Host != "0.0.0.0" {
		t.Errorf("expected 0.0.0.0, got %s", cfg.Host)
	}
	if cfg.Port != 9090 {
		t.Errorf("expected 9090, got %d", cfg.Port)
	}
	if cfg.LogLevel != "info" {
		t.Errorf("expected info (not overridden), got %s", cfg.LogLevel)
	}
	if !cfg.Debug {
		t.Error("expected debug=true from env")
	}
}

func TestEnvOverrideInvalidPort(t *testing.T) {
	tmpDir := t.TempDir()
	cfgFile := filepath.Join(tmpDir, "config.yaml")
	os.WriteFile(cfgFile, []byte("host: localhost\nport: 8080\n"), 0644)

	t.Setenv("CONFIGMAN_PORT", "not_a_number")

	cfg, err := Load(cfgFile)
	if err != nil {
		t.Fatal(err)
	}
	if cfg.Port != 8080 {
		t.Errorf("expected original port 8080 when env is invalid, got %d", cfg.Port)
	}
}
